SELECT
    DATE_FORMAT(create_time, '%Y-%m-%d') AS date,
    COUNT(*) AS orderCount,
    IFNULL(SUM(total_amount), 0) AS totalAmount
FROM herb_order
WHERE deleted = 0

    AND seller_id = #{userId}


    AND buyer_id = #{userId}


    AND create_time >= #{startDate}


    AND create_time <= #{endDate}

GROUP BY DATE_FORMAT(create_time, '%Y-%m-%d')
ORDER BY date

SELECT herb_name AS herbName, IFNULL(SUM(total_amount), 0) AS totalAmount, IFNULL(SUM(quantity), 0) AS totalQuantity, COUNT(*) AS orderCount FROM herb_order WHERE deleted = 0 AND order_status IN (2, 3, 4)
AND seller_id = #{userId}
AND buyer_id = #{userId}
GROUP BY herb_name ORDER BY totalAmount DESC LIMIT #{limit}

SELECT COUNT(*)
FROM herb_order
WHERE deleted = 0
  AND DATE(create_time) = CURDATE()

    AND seller_id = #{userId}


    AND buyer_id = #{userId}

SELECT IFNULL(SUM(total_amount), 0)
FROM herb_order
WHERE deleted = 0
  AND order_status IN (2, 3, 4)

    AND seller_id = #{userId}


    AND buyer_id = #{userId}
